var doc = {
  "id": 153,
  "title": "Other - WSL - Using Windows Docker With WSL",
  "url": "Other-O/WSL/Using_Windows_Docker_With_WSL.html",
  "body": " Step 1 Configure Windows Docker From the setting menu enable Expose daemon on tcp localhost 2375 without TLS Step 2 Install Docker and Docker Compose Within WSL Update the apt package list bash sudo apt-get update -y Install Docker s package dependencies bash sudo apt-get install -y apt-transport-https ca-certificates curl software-properties-common Download and add Docker s official public PGP key bash curl -fsSL https download docker com linux ubuntu gpg sudo apt-key add - Verify the fingerprint sudo apt-key fingerprint 0EBFCD88 Add the stable channel s Docker upstream repository bash sudo add-apt-repository deb arch amd64 https download docker com linux ubuntu lsb release -cs stable Update the apt package list for the new apt repo bash sudo apt-get update -y Install the latest version of Docker CE bash sudo apt-get install -y docker-ce Allow your user to access the Docker CLI without needing root access bash sudo usermod -aG docker USER Close and reopen WSL terminal for last command to take effect Step 3 Install Docker Compose bash Install Python and PIP sudo apt-get install -y python python-pip Install Docker Compose into your user s home directory pip install --user docker-compose Step 4 Check Path Create Environment Variables Ensure HOME local bin is on the WSL path echo PATH it missing add something similar to export PATH PATH HOME local bin to profile Add DOCKER HOST environment variable to bashrc bash echo export DOCKER HOST tcp localhost 2375 bashrc source bashrc Step 5 Check Everything Works bash docker info docker-compose --version If you get a permission denied error close open your terminal and try again hr p class pagedate This page was generated by a href GitHub Pages a Page last modified 20 09 23 12 16 p  Other - WSL - Using Windows Docker With WSL"
}
