var doc = {
  "id": 158,
  "title": "Postgres - Postgres - Reset Password",
  "url": "Postgres-P/Postgres_-_Reset_Password.html",
  "body": " Resetting the PostgreSQL Password Find the file pg hba conf - it may be located in etc postgresql-9 1 pg hba conf or var lib pgsql data pg hba conf back it up Place the following line as either the first uncommented line or as the only one local all all trust Restart your PostgreSQL server e g on Linux sudo etc init d postgresql restart or for systemd sudo service postgresql restart If the service daemon doesn t start reporting in log file local connections are not supported by this build you should change local all all trust to host all all 127 0 0 1 32 trust Connect as the postgres user psql -U postgres Reset the password ALTER USER my user name WITH PASSWORD super secure password Restore the old pg hba conf as it is very dangerous to keep around remove the line added above or replace with the backup copy Restart the server as described above hr p class pagedate This page was generated by a href GitHub Pages a Page last modified 20 09 07 12 32 p  Postgres - Postgres - Reset Password"
}
